What is the output of the following code snippet?
cpp
void mystery(int a, int &b) {
    a = a + 10;
    b = b + 10;
}

int main() {
    int x = 5, y = 5;
    mystery(x, y);
    cout << x << " " << y;
    return 0;
}

What is the output of the following code snippet?
cpp
void countCall() {
    static int count = 0;
    count++;
    cout << count << " ";
}

int main() {
    countCall();
    countCall();
    countCall();
    return 0;
}

